import React, { useState, useEffect, useCallback, useRef } from 'react';
import { fetchMarketSummary, fetchCandles, fetchDVOL, fetchOptionsVolume, fetchOrderBook, fetchHistoricalContext } from './services/deribitService';
import { generateSignal } from './services/tradingAlgo';
import { sendToWebhook, checkBridgeStatus, fetchBridgeState, clearRemoteBridge } from './services/webhookService';
import { sendTestMessage, sendSignalToTelegram } from './services/telegramService';
import { getIncomingHighImpactEvents, checkNewsImpactStatus, NewsStatus } from './services/newsService';
import { analyzeSignalWithAI, AIAnalysisResult } from './services/aiAnalyzer';
import { TradingSignal, AppConfig, LogEntry, LogType, MarketAnalysisState, EconomicEvent, SignalDirection, HistoricalTrade } from './types';
import { MQL5_CODE } from './utils/mqlCode';
import MarketStats from './components/MarketStats';
import TradeLog from './components/TradeLog';
import SignalCard from './components/SignalCard';
import NewsRadar from './components/NewsRadar';
import HistoryTable from './components/HistoryTable';

const CURRENT_VERSION = '35.0.0'; 
const MIN_SCORE_THRESHOLD = 75; 

// بيانات افتراضية لملء الفراغ في البداية
const SEED_HISTORY: HistoricalTrade[] = [
    { id: '1', asset: 'BTC-PERPETUAL', direction: SignalDirection.LONG, entryPrice: 65200, exitPrice: 67100, timestamp: Date.now() - 86400000, pnlPoints: 1900, outcome: 'WIN' },
    { id: '2', asset: 'ETH-PERPETUAL', direction: SignalDirection.SHORT, entryPrice: 3500, exitPrice: 3420, timestamp: Date.now() - 172800000, pnlPoints: 80, outcome: 'WIN' },
    { id: '3', asset: 'BTC-PERPETUAL', direction: SignalDirection.SHORT, entryPrice: 69000, exitPrice: 69500, timestamp: Date.now() - 259200000, pnlPoints: -500, outcome: 'LOSS' }
];

const DEFAULT_CONFIG: AppConfig = {
  telegramBotToken: '',
  telegramChatId: '',
  webhookUrl: 'http://127.0.0.1:3000',
  webhookSecret: 'ARKON_SECURE_PRIME_2025',
  riskRewardRatio: 2.5, 
  cooldownHours: 1,
  autoExecution: true,
  enableTrailing: true,
  equityProtectionPercent: 5.0, 
  maxAllocationPerTrade: 0.01, 
  maxPyramidingLayers: 3, 
  secureThreshold: 30.0, 
  partialClosePercent: 50.0,
  autoHedgeEnabled: true,
  trailingStepPoints: 150,
  newsBypassMinutes: 45,
  newsCooldownMinutes: 90,
  secureHedgeTrades: true,
  hunterMode: true,
  globalProfitTargetUSD: 1000,
  perTradeProfitTargetUSD: 100,
  maxOpenTrades: 5,
  disableInitialSL: true
};

const App: React.FC = () => {
  const [config, setConfig] = useState<AppConfig>(() => {
    const vCurrent = localStorage.getItem(`arkon_config_v${CURRENT_VERSION}`);
    if (vCurrent) return JSON.parse(vCurrent);
    return DEFAULT_CONFIG;
  });

  const [managedTrades, setManagedTrades] = useState<any[]>([]); 
  const [tradeHistory, setTradeHistory] = useState<HistoricalTrade[]>(SEED_HISTORY);
  const [logs, setLogs] = useState<LogEntry[]>([
      { id: 'start', timestamp: Date.now(), type: 'SYSTEM', message: 'ARKON Core Initialized. Awaiting Bridge Connection...' }
  ]);
  const [btcAnalysis, setBtcAnalysis] = useState<MarketAnalysisState | null>(null);
  const [ethAnalysis, setEthAnalysis] = useState<MarketAnalysisState | null>(null);
  const [newsEvents, setNewsEvents] = useState<EconomicEvent[]>([]);
  const [newsGuard, setNewsGuard] = useState<NewsStatus>({isPaused: false, reason: 'NORMAL', remainingMs: 0});

  const [isProcessing, setIsProcessing] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [activeTab, setActiveTab] = useState<'DASHBOARD' | 'HISTORY' | 'RISK' | 'SECURITY' | 'NEWS' | 'NOTIF' | 'EA' | 'SYSTEM'>('DASHBOARD');
  const [bridgeStatus, setBridgeStatus] = useState<boolean | null>(null);
  const [isTestingTg, setIsTestingTg] = useState(false);
  const [showSecret, setShowSecret] = useState(false);

  const [signals, setSignals] = useState<TradingSignal[]>([]);
  const sendingRef = useRef<Record<string, boolean>>({});
  const sentSignalsRef = useRef<Set<string>>(new Set());

  const addLog = useCallback((message: string, type: LogType = 'INFO', details?: string | object) => {
      setLogs(prev => [{ id: Math.random().toString(36).substr(2, 9), timestamp: Date.now(), type, message, details }, ...prev].slice(150)); 
  }, []);

  useEffect(() => {
    localStorage.setItem(`arkon_config_v${CURRENT_VERSION}`, JSON.stringify(config));
  }, [config]);

  const handleSendSignal = useCallback(async (signal: TradingSignal, overrideAction?: any): Promise<boolean> => {
    if (bridgeStatus === false) {
      addLog(`فشل: الجسر غير متصل`, 'ERROR');
      return false;
    }
    const actionType: any = overrideAction || 'ENTRY';
    const finalSignal = { ...signal };

    if (actionType === 'SECURE') {
        finalSignal.details = { ...finalSignal.details, secureThreshold: config.secureThreshold, partialClosePercent: config.partialClosePercent };
    }
    if (config.disableInitialSL && actionType === 'ENTRY') finalSignal.stopLoss = 0;

    if (sendingRef.current[signal.id] && actionType !== 'SECURE') return false;
    sendingRef.current[signal.id] = true;

    try {
        // AI Audit before sending if it's an entry
        if (actionType === 'ENTRY' && btcAnalysis) {
             addLog(`🤖 جاري إجراء تدقيق الذكاء الاصطناعي لـ ${signal.asset}...`, 'QUANT');
             const aiResult = await analyzeSignalWithAI(signal, btcAnalysis, tradeHistory);
             if (aiResult?.decision === 'REJECT') {
                 addLog(`❌ رفض الذكاء الاصطناعي: ${aiResult.reasoning}`, 'RISK');
                 if (!overrideAction) return false; // Stop auto-execution if AI rejects
             } else if (aiResult?.decision === 'APPROVE') {
                 addLog(`✅ موافقة الذكاء الاصطناعي: ${aiResult.reasoning}`, 'INFO');
             }
        }

        const result = await sendToWebhook(finalSignal, config.webhookUrl, 0.0, actionType, config.maxAllocationPerTrade, config.webhookSecret);
        if (result.success) {
            if (config.telegramBotToken && config.telegramChatId) {
                sendSignalToTelegram(finalSignal, config.telegramChatId, config.telegramBotToken, actionType, finalSignal.reasoning, config.webhookUrl).catch(() => {});
            }
            if (!overrideAction) sentSignalsRef.current.add(signal.id);
            addLog(`✅ تنفيذ: ${actionType} لـ ${signal.asset}`, 'EXEC');
            return true;
        } else {
            addLog(`رفض الجسر: ${result.error}`, 'ERROR');
        }
    } catch (err) { 
        addLog(`خطأ اتصال بالجسر`, 'ERROR'); 
    } finally { 
        sendingRef.current[signal.id] = false; 
    }
    return false;
  }, [config, bridgeStatus, addLog, btcAnalysis, tradeHistory]);

  const updateMarketData = useCallback(async () => {
    if (isProcessing) return;
    setIsProcessing(true);
    try {
      const isOnline = await checkBridgeStatus(config.webhookUrl);
      setBridgeStatus(isOnline);
      const bridgeState = await fetchBridgeState(config.webhookUrl);
      if (bridgeState && bridgeState.positions) setManagedTrades(bridgeState.positions);

      const events = await getIncomingHighImpactEvents();
      setNewsEvents(events);
      const guardResult = checkNewsImpactStatus(events, config.newsBypassMinutes, config.newsCooldownMinutes);
      setNewsGuard(guardResult);

      const processAsset = async (asset: 'BTC' | 'ETH') => {
        try {
            const summaries = await fetchMarketSummary(asset);
            const perp = summaries.find(s => s.instrument_name.includes('PERPETUAL'));
            if (perp) {
                const [dvol, optVol, candles, orderBook, dailyCandles] = await Promise.all([
                fetchDVOL(asset), fetchOptionsVolume(asset), fetchCandles(perp.instrument_name, '15'), 
                fetchOrderBook(perp.instrument_name), fetchHistoricalContext(perp.instrument_name)
                ]);
                const { signal, analysis } = generateSignal(asset, perp, summaries, candles, dailyCandles, orderBook, dvol, optVol);
                const enrichedAnalysis = { ...analysis, isNewsPaused: guardResult.isPaused, activeEvent: guardResult.event };
                if (asset === 'BTC') setBtcAnalysis(enrichedAnalysis); 
                else setEthAnalysis(enrichedAnalysis);

                if (signal && !sentSignalsRef.current.has(signal.id)) {
                    setSignals(prev => [signal, ...prev].slice(0, 50));
                    if (config.autoExecution && (!config.hunterMode || signal.qualityScore >= MIN_SCORE_THRESHOLD) && !guardResult.isPaused) {
                        handleSendSignal(signal);
                    }
                }
            }
        } catch (e) {
            console.error(`Error processing ${asset}:`, e);
        }
      };
      await processAsset('BTC');
      await processAsset('ETH');
    } catch (e) {
        console.error("Critical Update Error:", e);
    } finally { setIsProcessing(false); }
  }, [config, isProcessing, handleSendSignal]);

  useEffect(() => {
    const interval = setInterval(updateMarketData, 5000); 
    return () => clearInterval(interval);
  }, [updateMarketData]);

  const handleTestTg = async () => {
      setIsTestingTg(true);
      const res = await sendTestMessage(config.telegramBotToken, config.telegramChatId, config.webhookUrl);
      setIsTestingTg(false);
      addLog(res.success ? "تم إرسال رسالة اختبار Telegram بنجاح" : `خطأ في Telegram: ${res.error}`, res.success ? "SYSTEM" : "ERROR");
  };

  const clearBridgeData = async () => {
      if (window.confirm("هل أنت متأكد من تصفير بيانات الجسر بالكامل؟")) {
          const res = await clearRemoteBridge(config.webhookUrl);
          addLog(res ? "تم تصفير بيانات الجسر" : "فشل تصفير الجسر", res ? "SYSTEM" : "ERROR");
      }
  };

  return (
    <div className={`min-h-screen pb-12 px-6 pt-8 max-w-[1920px] mx-auto space-y-6 text-right font-sans transition-all duration-1000 ${newsGuard.isPaused ? (newsGuard.reason === 'POST_EVENT' ? 'bg-amber-950/10' : 'bg-rose-950/10') : 'bg-black'}`} dir="rtl">

      {/* Settings Modal */}
      {isSettingsOpen && (
          <div className="fixed inset-0 z-[250] flex items-center justify-center p-6 bg-black/90 backdrop-blur-3xl animate-in fade-in duration-300">
             <div className="glass-card w-full max-w-7xl rounded-[3rem] border-zinc-800 p-0 shadow-[0_0_200px_rgba(0,0,0,0.9)] relative overflow-hidden flex h-[85vh]">
                {/* Sidebar */}
                <div className="w-80 border-l border-zinc-900 bg-zinc-950/50 p-10 flex flex-col justify-between overflow-y-auto">
                    <div className="space-y-12">
                        <div className="flex items-center gap-4">
                            <div className="w-12 h-12 bg-amber-500 rounded-2xl flex items-center justify-center shadow-2xl shadow-amber-500/20 rotate-3 transition-transform hover:rotate-0">
                                <i className="fas fa-terminal text-black text-xl"></i>
                            </div>
                            <div>
                                <h2 className="text-xl font-black text-white leading-none">ARKON TERMINAL</h2>
                                <p className="text-[9px] text-zinc-500 font-bold uppercase tracking-widest mt-1">Prime Engine v{CURRENT_VERSION}</p>
                            </div>
                        </div>

                        <nav className="flex flex-col gap-2">
                            {[
                                {id: 'DASHBOARD', label: 'لوحة التحكم', icon: 'server'},
                                {id: 'HISTORY', label: 'سجل الصفقات', icon: 'book-open'},
                                {id: 'SECURITY', label: 'التشفير والربط', icon: 'key'},
                                {id: 'RISK', label: 'إدارة المخاطر', icon: 'chart-pie'},
                                {id: 'NOTIF', label: 'التنبيهات (TG)', icon: 'bell'},
                                {id: 'EA', label: 'كود MQL5', icon: 'code'},
                                {id: 'SYSTEM', label: 'الصيانة والتصفير', icon: 'hammer'}
                            ].map(tab => (
                                <button 
                                    key={tab.id} 
                                    onClick={() => setActiveTab(tab.id as any)} 
                                    className={`w-full flex items-center gap-4 px-6 py-4 rounded-2xl text-xs font-black transition-all ${activeTab === tab.id ? 'bg-white text-black shadow-xl scale-[1.05]' : 'text-zinc-500 hover:bg-white/5'}`}
                                >
                                    <i className={`fas fa-${tab.icon} w-5 text-center text-sm ${activeTab === tab.id ? 'text-amber-500' : 'text-zinc-800'}`}></i>
                                    {tab.label}
                                </button>
                            ))}
                        </nav>
                    </div>
                </div>

                {/* Content Area */}
                <div className="flex-1 bg-gradient-to-br from-zinc-900/10 to-transparent p-16 overflow-y-auto custom-scrollbar relative">
                    <button onClick={() => setIsSettingsOpen(false)} className="absolute top-10 left-10 w-12 h-12 rounded-full bg-zinc-900 border border-zinc-800 text-zinc-500 hover:text-white flex items-center justify-center transition-all hover:scale-110 z-10">
                        <i className="fas fa-times text-xl"></i>
                    </button>

                    <div className="max-w-3xl space-y-16 animate-in slide-in-from-left duration-500">
                        {activeTab === 'SECURITY' && (
                            <div className="space-y-12">
                                <header>
                                    <h3 className="text-3xl font-black text-white mb-2 uppercase tracking-tighter">أمن الجسر والتشفير</h3>
                                    <p className="text-zinc-500 text-sm">إعداد بروتوكولات الربط المشفرة مع MT5 لضمان سرية الصفقات.</p>
                                </header>
                                <div className="p-10 bg-zinc-950/50 rounded-[3rem] border border-zinc-800 space-y-10">
                                    <div className="space-y-4">
                                        <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest block">عنوان Webhook (Bridge URL)</label>
                                        <input type="text" value={config.webhookUrl} onChange={(e)=>setConfig({...config, webhookUrl: e.target.value})} className="w-full bg-zinc-900 border border-zinc-800 rounded-2xl px-8 py-5 text-white outline-none focus:border-amber-500 font-mono text-lg" placeholder="http://127.0.0.1:3000" />
                                    </div>
                                    <div className="space-y-4">
                                        <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest block">مفتاح الأمان (Webhook Secret)</label>
                                        <div className="relative">
                                            <input type={showSecret ? "text" : "password"} value={config.webhookSecret} onChange={(e)=>setConfig({...config, webhookSecret: e.target.value})} className="w-full bg-zinc-900 border border-zinc-800 rounded-2xl px-8 py-5 text-white outline-none focus:border-amber-500 font-mono text-lg pr-20" />
                                            <button onClick={()=>setShowSecret(!showSecret)} className="absolute right-6 top-1/2 -translate-y-1/2 text-zinc-500 hover:text-white uppercase text-[10px] font-black">
                                                {showSecret ? 'اخفاء' : 'عرض'}
                                            </button>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        )}

                        {activeTab === 'HISTORY' && (
                            <div className="space-y-12">
                                <header>
                                    <h3 className="text-3xl font-black text-white mb-2 uppercase tracking-tighter">سجل العمليات التاريخي</h3>
                                    <p className="text-zinc-500 text-sm">مراجعة أداء الخوارزمية والنتائج المحققة خلال الفترات السابقة.</p>
                                </header>
                                <HistoryTable trades={tradeHistory} />
                            </div>
                        )}

                        {activeTab === 'RISK' && (
                            <div className="space-y-12">
                                <header>
                                    <h3 className="text-3xl font-black text-white mb-2 uppercase tracking-tighter">إدارة المخاطر والسيولة</h3>
                                    <p className="text-zinc-500 text-sm">التحكم في حجم اللوتات وتوزيع المحفظة.</p>
                                </header>
                                <div className="grid grid-cols-2 gap-8">
                                    <div className="p-8 bg-zinc-950/50 rounded-[2.5rem] border border-zinc-800 space-y-4">
                                        <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">المخاطرة لكل صفقة (%)</label>
                                        <input type="number" step="0.01" value={config.maxAllocationPerTrade} onChange={(e)=>setConfig({...config, maxAllocationPerTrade: parseFloat(e.target.value)})} className="w-full bg-zinc-900 border border-zinc-800 rounded-2xl px-6 py-4 text-white font-mono text-xl" />
                                    </div>
                                    <div className="p-8 bg-zinc-950/50 rounded-[2.5rem] border border-zinc-800 space-y-4">
                                        <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">أقصى عدد صفقات مفتوحة</label>
                                        <input type="number" value={config.maxOpenTrades} onChange={(e)=>setConfig({...config, maxOpenTrades: parseInt(e.target.value)})} className="w-full bg-zinc-900 border border-zinc-800 rounded-2xl px-6 py-4 text-white font-mono text-xl" />
                                    </div>
                                </div>
                            </div>
                        )}

                        {activeTab === 'EA' && (
                            <div className="space-y-8">
                                <div className="flex justify-between items-center">
                                    <h3 className="text-3xl font-black text-white uppercase tracking-tighter">ARKON MT5 RELAY</h3>
                                    <button onClick={() => {navigator.clipboard.writeText(MQL5_CODE); addLog("تم نسخ الكود للمحافظة", "SYSTEM")}} className="px-6 py-3 bg-white text-black text-[10px] font-black rounded-xl hover:bg-amber-500 transition-all uppercase tracking-widest">نسخ الكود الكامل</button>
                                </div>
                                <div className="bg-black/80 rounded-3xl border border-zinc-800 p-8 h-[400px] overflow-y-auto custom-scrollbar font-mono text-xs text-emerald-500/70 leading-relaxed whitespace-pre pr-8" dir="ltr">
                                    {MQL5_CODE}
                                </div>
                            </div>
                        )}

                        {activeTab === 'SYSTEM' && (
                            <div className="space-y-12">
                                <header>
                                    <h3 className="text-3xl font-black text-white mb-2 uppercase tracking-tighter">صيانة النظام</h3>
                                    <p className="text-zinc-500 text-sm">أوامر التحكم الجذري في حالة المحرك ومسح سجلات الذاكرة.</p>
                                </header>
                                <button onClick={clearBridgeData} className="w-full p-8 bg-rose-500/10 border border-rose-500/20 rounded-[2.5rem] flex items-center justify-between group hover:bg-rose-500 transition-all">
                                    <div className="text-right">
                                        <span className="block text-xl font-black text-rose-500 group-hover:text-black">تصفير الجسر (Force Clear)</span>
                                        <span className="block text-xs text-zinc-500 group-hover:text-black/60 uppercase font-black mt-1">حذف كافة الصفقات العالقة وإعادة تهيئة الذاكرة</span>
                                    </div>
                                    <i className="fas fa-trash-alt text-2xl text-rose-500 group-hover:text-black"></i>
                                </button>
                            </div>
                        )}
                    </div>
                </div>
             </div>
          </div>
      )}

      {/* Main App Layout */}
      <header className="flex justify-between items-center mb-10 px-4">
          <div className="flex items-center gap-8">
              <div className="w-20 h-20 bg-white rounded-[2.5rem] flex items-center justify-center shadow-[0_0_50px_rgba(255,255,255,0.1)] relative group cursor-pointer overflow-hidden">
                  <span className="text-black font-black text-4xl relative z-10">A</span>
                  <div className="absolute inset-0 bg-gradient-to-tr from-amber-500 to-amber-300 opacity-0 group-hover:opacity-100 transition-all duration-500"></div>
              </div>
              <div>
                  <h1 className="text-5xl font-black text-white uppercase tracking-tighter">ARKON <span className="text-zinc-700 font-light">PRIME</span></h1>
                  <div className="flex items-center gap-4 mt-2">
                      <span className="text-[10px] bg-zinc-900 border border-zinc-800 text-zinc-500 px-4 py-1.5 rounded-full font-black uppercase tracking-[0.3em]">Quantum Engine v{CURRENT_VERSION}</span>
                      <div className="flex items-center gap-3">
                          <div className={`w-2.5 h-2.5 rounded-full ${bridgeStatus ? 'bg-emerald-500 shadow-[0_0_15px_#10b981]' : 'bg-rose-500 shadow-[0_0_15px_#f43f5e]'}`}></div>
                          <span className="text-[10px] font-black text-zinc-600 uppercase tracking-widest">{bridgeStatus ? 'Relay Active' : 'Relay Offline'}</span>
                      </div>
                  </div>
              </div>
          </div>

          <div className="flex items-center gap-4">
              <button onClick={() => setActiveTab(activeTab === 'HISTORY' ? 'DASHBOARD' : 'HISTORY')} className="px-8 py-4 bg-zinc-900 border border-zinc-800 text-white text-[10px] font-black uppercase tracking-widest rounded-3xl hover:bg-zinc-800 transition-all">
                  {activeTab === 'HISTORY' ? 'العودة للرئيسية' : 'سجل العمليات'}
              </button>
              <button onClick={() => setIsSettingsOpen(true)} className="group flex items-center gap-5 bg-white border border-transparent hover:bg-amber-500 px-10 py-5 rounded-[2.5rem] transition-all shadow-2xl hover:shadow-amber-500/20 active:scale-95">
                   <div className="text-right">
                       <span className="block text-[10px] font-black text-zinc-400 group-hover:text-black/60 uppercase tracking-widest">System Control</span>
                       <span className="block text-sm font-black text-black">الإعدادات</span>
                   </div>
                   <div className="w-12 h-12 rounded-2xl bg-zinc-100 flex items-center justify-center group-hover:bg-black transition-all">
                       <i className="fas fa-sliders text-xl text-black group-hover:text-white"></i>
                   </div>
              </button>
          </div>
      </header>

      {activeTab === 'HISTORY' ? (
          <div className="animate-in fade-in slide-in-from-bottom duration-500">
              <HistoryTable trades={tradeHistory} />
          </div>
      ) : (
          <main className="grid grid-cols-1 xl:grid-cols-12 gap-10 items-stretch animate-in fade-in duration-500">
              <div className="xl:col-span-8 space-y-10">
                  <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
                      <MarketStats title="BITCOIN CORE" state={btcAnalysis} />
                      <MarketStats title="ETHEREUM CORE" state={ethAnalysis} />
                  </div>

                  <div className="glass-card rounded-[4rem] p-12 border border-zinc-900 bg-zinc-950/20 shadow-2xl">
                      <div className="flex justify-between items-center mb-12">
                          <div className="flex items-center gap-6">
                              <div className="w-2 h-10 bg-amber-500 rounded-full shadow-[0_0_20px_#f59e0b]"></div>
                              <h3 className="text-3xl font-black text-white uppercase tracking-tighter">Quantum <span className="text-zinc-700">Signals</span></h3>
                          </div>
                          <div className="flex gap-4">
                              <div className="text-right px-6 py-3 bg-zinc-900/50 rounded-2xl border border-zinc-800">
                                 <span className="block text-[8px] text-zinc-600 font-black uppercase">Active Streams</span>
                                 <span className="text-sm font-mono font-bold text-amber-500">{signals.length} LIVE</span>
                              </div>
                          </div>
                      </div>

                      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                          {signals.map(sig => (
                            <SignalCard 
                              key={sig.id} 
                              signal={sig} 
                              onSend={handleSendSignal} 
                              sending={sendingRef.current[sig.id] || false} 
                              userRiskCap={config.maxAllocationPerTrade} 
                              isActive={managedTrades.some(t => t.signalId === sig.id)}
                              isSystemLocked={newsGuard.isPaused}
                            />
                          ))}
                          {signals.length === 0 && (
                              <div className="col-span-full py-20 text-center space-y-4">
                                  <i className="fas fa-radar text-4xl text-zinc-800 animate-pulse"></i>
                                  <p className="text-zinc-700 text-xs font-black uppercase tracking-[0.5em]">Scanning Market Frequencies...</p>
                              </div>
                          )}
                      </div>
                  </div>
              </div>

              <div className="xl:col-span-4 space-y-10 flex flex-col h-full">
                  <NewsRadar 
                    events={newsEvents} 
                    isPaused={newsGuard.isPaused} 
                    activeEvent={newsGuard.event} 
