  secureHedgeTrades: true,
  hunterMode: true,
  globalProfitTargetUSD: 500,
  perTradeProfitTargetUSD: 100,
  maxOpenTrades: 4,
  disableInitialSL: false
};

const App: React.FC = () => {
  const [config, setConfig] = useState<AppConfig>(() => {
    const vCurrent = localStorage.getItem(`arkon_config_v${CURRENT_VERSION}`);
    if (vCurrent) return JSON.parse(vCurrent);
    return DEFAULT_CONFIG;
  });

  const [managedTrades, setManagedTrades] = useState<any[]>([]); 
  const [logs, setLogs] = useState<LogEntry[]>([
      { id: 'start', timestamp: Date.now(), type: 'SYSTEM', message: 'ARKON Quant Core v38.0. Settings Restored.' }
  ]);
  const [btcAnalysis, setBtcAnalysis] = useState<MarketAnalysisState | null>(null);
  const [ethAnalysis, setEthAnalysis] = useState<MarketAnalysisState | null>(null);
  const [newsEvents, setNewsEvents] = useState<EconomicEvent[]>([]);
  const [newsGuard, setNewsGuard] = useState<NewsStatus>({isPaused: false, reason: 'NORMAL', remainingMs: 0});

  const [isProcessing, setIsProcessing] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [settingsTab, setSettingsTab] = useState<'GENERAL' | 'RISK' | 'SECURE' | 'TELEGRAM' | 'NEWS' | 'BRIDGE'>('GENERAL');
  const [bridgeStatus, setBridgeStatus] = useState<boolean | null>(null);
  const [signals, setSignals] = useState<TradingSignal[]>([]);
  const sendingRef = useRef<Record<string, boolean>>({});
  const sentSignalsRef = useRef<Set<string>>(new Set());

  const addLog = useCallback((message: string, type: LogType = 'INFO', details?: string | object) => {
      setLogs(prev => [{ id: Math.random().toString(36).substr(2, 9), timestamp: Date.now(), type, message, details }, ...prev].slice(150)); 
  }, []);

  useEffect(() => {
    localStorage.setItem(`arkon_config_v${CURRENT_VERSION}`, JSON.stringify(config));
  }, [config]);

  const handleSendSignal = useCallback(async (signal: any, actionType: any = 'ENTRY'): Promise<boolean> => {
    if (!bridgeStatus) {
      addLog(`فشل: الجسر غير متصل`, 'ERROR');
      return false;
    }

    if (actionType === 'ENTRY' && managedTrades.length >= config.maxOpenTrades) {
        addLog(`تم بلوغ الحد الأقصى للصيد (${config.maxOpenTrades})`, 'RISK');
        return false;
    }

    const finalSignal = { ...signal };
    const reqId = (signal.id || signal.signalId) + actionType;
    if (sendingRef.current[reqId]) return false;
    sendingRef.current[reqId] = true;

    try {
        const result = await sendToWebhook(finalSignal, config.webhookUrl, 0.0, actionType, config.maxAllocationPerTrade, config.webhookSecret);
        if (result.success) {
            addLog(`🚀 تنفيذ: ${actionType} لـ ${signal.asset}`, 'EXEC');
            if (config.telegramBotToken && config.telegramChatId) {
                sendSignalToTelegram(finalSignal, config.telegramChatId, config.telegramBotToken, actionType, "", config.webhookUrl).catch(() => {});
            }
            if (actionType === 'ENTRY') sentSignalsRef.current.add(signal.id);
            return true;
        }
    } catch (err) { addLog(`خطأ اتصال بالجسر`, 'ERROR'); } 
    finally { sendingRef.current[reqId] = false; }
    return false;
  }, [config, bridgeStatus, addLog, managedTrades.length]);

  const updateMarketData = useCallback(async () => {
    if (isProcessing) return;
    setIsProcessing(true);
    try {
      const isOnline = await checkBridgeStatus(config.webhookUrl);
      setBridgeStatus(isOnline);
      const bridgeState = await fetchBridgeState(config.webhookUrl);
      if (bridgeState && bridgeState.positions) setManagedTrades(bridgeState.positions);

      const events = await getIncomingHighImpactEvents();
      setNewsEvents(events);
      const guardResult = checkNewsImpactStatus(events, config.newsBypassMinutes, config.newsCooldownMinutes);
      setNewsGuard(guardResult);

      const processAsset = async (asset: 'BTC' | 'ETH') => {
        try {
            const summaries = await fetchMarketSummary(asset);
            const perp = summaries.find(s => s.instrument_name.includes('PERPETUAL'));
            if (perp) {
                const [dvol, optVol, candles, orderBook, dailyCandles] = await Promise.all([
                fetchDVOL(asset), fetchOptionsVolume(asset), fetchCandles(perp.instrument_name, '15'), 
                fetchOrderBook(perp.instrument_name), fetchHistoricalContext(perp.instrument_name)
                ]);
                const { signal, analysis } = generateSignal(asset, perp, summaries, candles, dailyCandles, orderBook, dvol, optVol);
                const enrichedAnalysis = { ...analysis, isNewsPaused: guardResult.isPaused, activeEvent: guardResult.event };
                if (asset === 'BTC') setBtcAnalysis(enrichedAnalysis); 
                else setEthAnalysis(enrichedAnalysis);

                if (signal && !sentSignalsRef.current.has(signal.id)) {
                    setSignals(prev => [signal, ...prev].slice(0, 50));
                    if (config.autoExecution && !guardResult.isPaused) {
                        if (!config.hunterMode || signal.qualityScore >= 80) handleSendSignal(signal);
                    }
                }
            }
        } catch (e) { console.error(`Feed Error ${asset}:`, e); }
      };
      await processAsset('BTC');
      await processAsset('ETH');
    } finally { setIsProcessing(false); }
  }, [config, isProcessing, handleSendSignal]);

  useEffect(() => {
    const interval = setInterval(updateMarketData, 4000); 
    return () => clearInterval(interval);
  }, [updateMarketData]);

  const totalPnL = managedTrades.reduce((acc, t) => acc + (t.pnl || 0), 0);

  return (
    <div className="min-h-screen pb-12 px-6 pt-8 max-w-[1920px] mx-auto space-y-6 text-right font-sans bg-[#050507]" dir="rtl">

      {/* Settings Modal - Complete & Professional */}
      {isSettingsOpen && (
          <div className="fixed inset-0 z-[250] flex items-center justify-center p-6 bg-black/98 backdrop-blur-2xl">
             <div className="glass-card w-full max-w-6xl rounded-[3rem] border-zinc-800 p-0 shadow-[0_0_100px_rgba(0,0,0,0.5)] flex h-[80vh] overflow-hidden">
                {/* Sidebar */}
                <div className="w-64 bg-zinc-950/50 border-l border-zinc-900 p-8 flex flex-col gap-2">
                    <h3 className="text-zinc-500 font-black text-[9px] uppercase tracking-widest mb-6">قائمة الإعدادات</h3>
                    {[
                        {id: 'GENERAL', label: 'عام والتنفيذ', icon: 'bolt'},
                        {id: 'RISK', label: 'إدارة المخاطر', icon: 'shield-halved'},
                        {id: 'SECURE', label: 'تأمين الأرباح', icon: 'lock'},
                        {id: 'TELEGRAM', label: 'التليجرام', icon: 'paper-plane'},
                        {id: 'NEWS', label: 'فلتر الأخبار', icon: 'newspaper'},
                        {id: 'BRIDGE', label: 'الجسر والأمان', icon: 'link'}
                    ].map(tab => (
                        <button 
                            key={tab.id} 
                            onClick={() => setSettingsTab(tab.id as any)}
                            className={`flex items-center gap-4 px-5 py-4 rounded-2xl text-xs font-black transition-all ${settingsTab === tab.id ? 'bg-white text-black' : 'text-zinc-500 hover:bg-white/5'}`}
                        >
                            <i className={`fas fa-${tab.icon} w-5`}></i> {tab.label}
                        </button>
                    ))}
                </div>

                {/* Content */}
                <div className="flex-1 p-16 overflow-y-auto custom-scrollbar relative">
                    <button onClick={() => setIsSettingsOpen(false)} className="absolute top-10 left-10 text-zinc-500 hover:text-white"><i className="fas fa-times text-2xl"></i></button>

                    <div className="max-w-3xl space-y-12 animate-in slide-in-from-left duration-300">
                        {settingsTab === 'GENERAL' && (
                            <div className="space-y-10">
                                <h2 className="text-3xl font-black text-white italic">إعدادات النظام العامة</h2>
                                <div className="grid grid-cols-2 gap-8">
                                    <div className="p-6 bg-zinc-900/50 rounded-2xl border border-zinc-800 flex justify-between items-center">
                                        <label className="text-xs font-black text-zinc-400">التنفيذ الآلي (Auto-Execution)</label>
                                        <input type="checkbox" checked={config.autoExecution} onChange={(e)=>setConfig({...config, autoExecution: e.target.checked})} className="w-6 h-6 accent-amber-500" />
                                    </div>
                                    <div className="p-6 bg-zinc-900/50 rounded-2xl border border-zinc-800 flex justify-between items-center">
                                        <label className="text-xs font-black text-zinc-400">وضع الصياد (Hunter Mode 80%+)</label>
                                        <input type="checkbox" checked={config.hunterMode} onChange={(e)=>setConfig({...config, hunterMode: e.target.checked})} className="w-6 h-6 accent-amber-500" />
                                    </div>
                                    <div className="space-y-3">
                                        <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">ساعات التبريد بين الصفقات</label>
                                        <input type="number" value={config.cooldownHours} onChange={(e)=>setConfig({...config, cooldownHours: parseFloat(e.target.value)})} className="w-full bg-zinc-900 border border-zinc-800 rounded-xl px-6 py-4 text-white font-mono" />
                                    </div>
                                </div>
                            </div>
                        )}

                        {settingsTab === 'RISK' && (
                            <div className="space-y-10">
                                <h2 className="text-3xl font-black text-white italic">بروتوكول إدارة المخاطر</h2>
                                <div className="grid grid-cols-2 gap-8">
                                    <div className="space-y-3">
                                        <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">أقصى مخاطرة لكل مركز (%)</label>
                                        <input type="number" step="0.01" value={config.maxAllocationPerTrade} onChange={(e)=>setConfig({...config, maxAllocationPerTrade: parseFloat(e.target.value)})} className="w-full bg-zinc-900 border border-zinc-800 rounded-xl px-6 py-4 text-white font-mono" />
                                    </div>
                                    <div className="space-y-3">
                                        <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">عدد الصفقات المفتوحة (Max Trades)</label>
                                        <input type="number" value={config.maxOpenTrades} onChange={(e)=>setConfig({...config, maxOpenTrades: parseInt(e.target.value)})} className="w-full bg-zinc-900 border border-zinc-800 rounded-xl px-6 py-4 text-white font-mono" />
                                    </div>
                                    <div className="space-y-3">
                                        <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">نسبة حماية المحفظة (Equity Protection %)</label>
                                        <input type="number" value={config.equityProtectionPercent} onChange={(e)=>setConfig({...config, equityProtectionPercent: parseFloat(e.target.value)})} className="w-full bg-zinc-900 border border-zinc-800 rounded-xl px-6 py-4 text-white font-mono" />
                                    </div>
                                    <div className="space-y-3">
                                        <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">نسبة العائد للمخاطرة (RR Ratio)</label>
                                        <input type="number" value={config.riskRewardRatio} onChange={(e)=>setConfig({...config, riskRewardRatio: parseFloat(e.target.value)})} className="w-full bg-zinc-900 border border-zinc-800 rounded-xl px-6 py-4 text-white font-mono" />
                                    </div>
                                </div>
                            </div>
                        )}

                        {settingsTab === 'SECURE' && (
                            <div className="space-y-10">
                                <h2 className="text-3xl font-black text-white italic">تأمين الأرباح والإغلاق الجزئي</h2>
                                <div className="grid grid-cols-2 gap-8">
                                    <div className="space-y-3">
                                        <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">عتبة تأمين الربح ($ USD)</label>
                                        <input type="number" value={config.secureThreshold} onChange={(e)=>setConfig({...config, secureThreshold: parseFloat(e.target.value)})} className="w-full bg-zinc-900 border border-zinc-800 rounded-xl px-6 py-4 text-white font-mono" />
                                    </div>
                                    <div className="space-y-3">
                                        <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">نسبة الإغلاق الجزئي عند التأمين (%)</label>
                                        <input type="number" value={config.partialClosePercent} onChange={(e)=>setConfig({...config, partialClosePercent: parseFloat(e.target.value)})} className="w-full bg-zinc-900 border border-zinc-800 rounded-xl px-6 py-4 text-white font-mono" />
                                    </div>
                                    <div className="p-6 bg-zinc-900/50 rounded-2xl border border-zinc-800 flex justify-between items-center">
                                        <label className="text-xs font-black text-zinc-400">تفعيل الـ Trailing Stop</label>
                                        <input type="checkbox" checked={config.enableTrailing} onChange={(e)=>setConfig({...config, enableTrailing: e.target.checked})} className="w-6 h-6 accent-emerald-500" />
                                    </div>
                                    <div className="space-y-3">
                                        <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">خطوة الـ Trailing (بالنقطة)</label>
                                        <input type="number" value={config.trailingStepPoints} onChange={(e)=>setConfig({...config, trailingStepPoints: parseInt(e.target.value)})} className="w-full bg-zinc-900 border border-zinc-800 rounded-xl px-6 py-4 text-white font-mono" />
                                    </div>
                                </div>
                            </div>
                        )}

                        {settingsTab === 'TELEGRAM' && (
                            <div className="space-y-10">
                                <h2 className="text-3xl font-black text-white italic">إشعارات التليجرام الفورية</h2>
                                <div className="space-y-6">
                                    <div className="space-y-3">
                                        <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">توكن البوت (Bot Token)</label>
                                        <input type="password" value={config.telegramBotToken} onChange={(e)=>setConfig({...config, telegramBotToken: e.target.value})} className="w-full bg-zinc-900 border border-zinc-800 rounded-xl px-6 py-4 text-white font-mono" placeholder="712345678:AAH..." />
                                    </div>
                                    <div className="space-y-3">
                                        <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">رقم الدردشة (Chat ID)</label>
                                        <input type="text" value={config.telegramChatId} onChange={(e)=>setConfig({...config, telegramChatId: e.target.value})} className="w-full bg-zinc-900 border border-zinc-800 rounded-xl px-6 py-4 text-white font-mono" placeholder="-100..." />
                                    </div>
                                    <button onClick={async () => {
                                        const res = await sendTestMessage(config.telegramBotToken, config.telegramChatId, config.webhookUrl);
                                        addLog(res.success ? "✅ تم إرسال رسالة اختبار بنجاح" : "❌ فشل اختبار التليجرام", res.success ? "SYSTEM" : "ERROR");
                                    }} className="px-10 py-4 bg-amber-500 text-black font-black rounded-xl hover:scale-105 transition-all">اختبار الاتصال بالبوت</button>
                                </div>
                            </div>
                        )}

                        {settingsTab === 'NEWS' && (
                            <div className="space-y-10">
                                <h2 className="text-3xl font-black text-white italic">درع حماية الأخبار</h2>
                                <div className="grid grid-cols-2 gap-8">
                                    <div className="space-y-3">
                                        <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">إيقاف التداول قبل الخبر (دقيقة)</label>
                                        <input type="number" value={config.newsBypassMinutes} onChange={(e)=>setConfig({...config, newsBypassMinutes: parseInt(e.target.value)})} className="w-full bg-zinc-900 border border-zinc-800 rounded-xl px-6 py-4 text-white font-mono" />
                                    </div>
                                    <div className="space-y-3">
                                        <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">فترة التبريد بعد الخبر (دقيقة)</label>
                                        <input type="number" value={config.newsCooldownMinutes} onChange={(e)=>setConfig({...config, newsCooldownMinutes: parseInt(e.target.value)})} className="w-full bg-zinc-900 border border-zinc-800 rounded-xl px-6 py-4 text-white font-mono" />
                                    </div>
                                </div>
                            </div>
                        )}

                        {settingsTab === 'BRIDGE' && (
                            <div className="space-y-10">
                                <h2 className="text-3xl font-black text-white italic">أمان الجسر والربط المشفر</h2>
                                <div className="space-y-6">
                                    <div className="space-y-3">
                                        <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">رابط الـ Webhook الخاص بالجسر</label>
                                        <input type="text" value={config.webhookUrl} onChange={(e)=>setConfig({...config, webhookUrl: e.target.value})} className="w-full bg-zinc-900 border border-zinc-800 rounded-xl px-6 py-4 text-white font-mono" />
                                    </div>
                                    <div className="space-y-3">
                                        <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">مفتاح الأمان السري (Webhook Secret)</label>
                                        <input type="password" value={config.webhookSecret} onChange={(e)=>setConfig({...config, webhookSecret: e.target.value})} className="w-full bg-zinc-900 border border-zinc-800 rounded-xl px-6 py-4 text-white font-mono" />
                                    </div>
                                    <button onClick={async () => {
                                        if(window.confirm("حذف كافة الصفقات العالقة وإعادة التصفير؟")) {
                                            const res = await clearRemoteBridge(config.webhookUrl);
                                            addLog(res ? "✅ تم تصفير الجسر" : "❌ فشل التصفير", "SYSTEM");
                                        }
                                    }} className="px-10 py-4 bg-rose-500/10 border border-rose-500/20 text-rose-500 font-black rounded-xl hover:bg-rose-500 hover:text-white transition-all">تصفير بيانات الجسر بالكامل</button>
                                </div>
                            </div>
                        )}
                    </div>

                    <div className="mt-20 pt-10 border-t border-zinc-900 flex justify-end">
                        <button onClick={() => { 
                            localStorage.setItem(`arkon_config_v${CURRENT_VERSION}`, JSON.stringify(config)); 
                            setIsSettingsOpen(false); 
                            addLog("💾 تم حفظ الإعدادات بنجاح", "SYSTEM");
                        }} className="px-16 py-5 bg-white text-black font-black rounded-2xl uppercase tracking-widest hover:bg-amber-500 transition-all shadow-2xl shadow-white/10">حفظ وتطبيق البروتوكول</button>
                    </div>
                </div>
             </div>
          </div>
      )}

      {/* Header */}
      <header className="flex justify-between items-center mb-10 px-4">
          <div className="flex items-center gap-8">
              <div className="w-16 h-16 bg-white rounded-2xl flex items-center justify-center shadow-2xl group cursor-pointer hover:rotate-12 transition-all">
                  <span className="text-black font-black text-3xl">A</span>
              </div>
              <div>
                  <h1 className="text-4xl font-black text-white uppercase italic tracking-tighter">ARKON <span className="text-amber-500">QUANT</span> <span className="text-zinc-800 not-italic ml-2">v{CURRENT_VERSION}</span></h1>
                  <div className="flex items-center gap-4 mt-1">
                      <div className={`w-2.5 h-2.5 rounded-full ${bridgeStatus ? 'bg-emerald-500 shadow-[0_0_12px_#10b981]' : 'bg-rose-500 shadow-[0_0_12px_#f43f5e]'}`}></div>
                      <span className="text-[10px] font-black text-zinc-600 uppercase tracking-[0.2em]">{bridgeStatus ? 'MT5 Relay Connected' : 'MT5 Bridge Offline'}</span>
                  </div>
              </div>
          </div>

          <div className="flex items-center gap-6">
              <div className="text-right px-8 py-3 border-r border-zinc-800">
                  <span className="text-[9px] text-zinc-600 font-black uppercase block tracking-widest">Live Portfolio PnL</span>
                  <span className={`text-2xl font-mono font-black ${totalPnL >= 0 ? 'text-emerald-500' : 'text-rose-500'}`}>
                      {totalPnL >= 0 ? '+' : ''}${totalPnL.toFixed(2)}
                  </span>
              </div>
              <button onClick={() => setIsSettingsOpen(true)} className="group bg-zinc-900 border border-zinc-800 hover:border-amber-500/50 px-8 py-4 rounded-2xl transition-all flex items-center gap-4 shadow-xl">
                  <span className="text-[10px] font-black text-white uppercase tracking-widest">إدارة النظام</span>
                  <i className="fas fa-sliders text-amber-500 group-hover:rotate-90 transition-all"></i>
              </button>
          </div>
      </header>

      {/* Main UI */}
      {activeTab === 'HISTORY' ? (
          <HistoryTable trades={[]} />
      ) : (
          <main className="grid grid-cols-1 xl:grid-cols-12 gap-10">
              <div className="xl:col-span-8 space-y-10">
                  <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
                      <MarketStats title="BTC/USD ALGO" state={btcAnalysis} />
                      <MarketStats title="ETH/USD ALGO" state={ethAnalysis} />
                  </div>

                  <div className="glass-card rounded-[3rem] p-10 border border-zinc-900 bg-zinc-950/20 shadow-2xl relative overflow-hidden">
                      <div className="flex justify-between items-center mb-10">
                          <h3 className="text-2xl font-black text-white italic uppercase tracking-tighter">تدفق الإشارات (Quantum Stream)</h3>
                          <div className="flex gap-4">
                            <span className="text-[10px] text-zinc-600 font-black uppercase">{signals.length} LIVE SIGNALS</span>
                          </div>
                      </div>

                      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                          {signals.map(sig => (
                            <SignalCard 
