                              isActive={managedTrades.some(t => t.signalId === sig.id)}
                              isSystemLocked={newsGuard.isPaused}
                            />
                          ))}
                      </div>
                  </div>
              </div>

              <div className="xl:col-span-4 space-y-10 flex flex-col">
                  <NewsRadar events={newsEvents} isPaused={newsGuard.isPaused} activeEvent={newsGuard.event} newsStatus={{ reason: newsGuard.reason, remainingMs: newsGuard.remainingMs }} />

                  <div className="glass-card rounded-[3rem] border border-zinc-900 p-10 flex flex-col gap-8 bg-zinc-950/40 min-h-[500px] shadow-2xl">
                      <div className="flex justify-between items-center border-b border-zinc-900 pb-4">
                        <h3 className="text-xl font-black text-white italic uppercase tracking-widest">المحفظة النشطة</h3>
                        <span className="text-[10px] font-mono text-zinc-600">[{managedTrades.length}] TRADES</span>
                      </div>

                      <div className="space-y-4 flex-1 overflow-y-auto custom-scrollbar">
