                          ) : (
                            managedTrades.map((trade, idx) => (
                                <div key={idx} className="p-6 rounded-3xl bg-zinc-900/90 border border-zinc-800 space-y-5 group hover:border-zinc-600 transition-all">
                                    <div className="flex justify-between items-start">
                                        <div className="flex items-center gap-4">
                                            <div className={`w-1.5 h-10 rounded-full ${trade.direction === 'LONG' ? 'bg-emerald-500 shadow-[0_0_10px_#10b981]' : 'bg-rose-500 shadow-[0_0_10px_#f43f5e]'}`}></div>
