                                            </div>
                                        </div>
                                        <div className="text-right">
                                            <span className={`text-2xl font-mono font-black ${trade.pnl >= 0 ? 'text-emerald-500' : 'text-rose-500'}`}>
                                                {trade.pnl >= 0 ? '+' : ''}${trade.pnl.toFixed(2)}
                                            </span>
                                            <div className="text-[8px] font-black text-zinc-700 uppercase mt-1">Live Profit</div>
                                        </div>
                                    </div>

                                    <div className="grid grid-cols-2 gap-4">
                                        <button 
                                            onClick={() => handleSendSignal(trade, 'SECURE')}
                                            disabled={sendingRef.current[trade.signalId + 'SECURE']}
                                            className="bg-amber-500/10 border border-amber-500/20 hover:bg-amber-500 hover:text-black py-3 rounded-xl text-[9px] font-black uppercase transition-all flex items-center justify-center gap-2"
                                        >
                                            <i className="fas fa-shield-halved"></i> SECURE
                                        </button>
                                        <button 
                                            onClick={() => handleSendSignal(trade, 'EXIT')}
                                            disabled={sendingRef.current[trade.signalId + 'EXIT']}
                                            className="bg-rose-500/10 border border-rose-500/20 hover:bg-rose-500 hover:text-white py-3 rounded-xl text-[9px] font-black uppercase transition-all flex items-center justify-center gap-2"
                                        >
                                            <i className="fas fa-times-circle"></i> EXIT TRADE
                                        </button>
                                    </div>
                                </div>
                            ))
                          )}
                      </div>

                      <TradeLog logs={logs} activeTradesCount={managedTrades.length} managedTrades={managedTrades} onCloseTrade={()=>{}} />
                  </div>
              </div>
          </main>
      )}

      {/* Nav */}
      <footer className="fixed bottom-0 left-0 right-0 bg-black/90 backdrop-blur-xl border-t border-zinc-900 py-4 px-10 flex justify-center items-center gap-16 z-[100]">
          <button onClick={() => setActiveTab('DASHBOARD')} className={`text-[10px] font-black uppercase tracking-[0.4em] transition-all ${activeTab === 'DASHBOARD' ? 'text-amber-500' : 'text-zinc-700 hover:text-zinc-400'}`}>Dashboard Control</button>
          <button onClick={() => setActiveTab('HISTORY')} className={`text-[10px] font-black uppercase tracking-[0.4em] transition-all ${activeTab === 'HISTORY' ? 'text-amber-500' : 'text-zinc-700 hover:text-zinc-400'}`}>Historical Ledger</button>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
